const req = $input.first().json;
return [{ json: {
  client_id: req.body.client_id,
  timestamp: req.headers['x-caiac-timestamp'],
  signature: req.headers['x-caiac-signature'],
  token: req.body.token
} }];

const session = $input.first().json;
if (!session || !session.user_id) throw new Error('Invalid or expired token');
return [{ json: {
  user_id: session.user_id,
  role: session.role,
  client_id: session.client_id,
  slug: session.slug,
  name: session.name,
  email: session.email,
  message: $('Receive Chat Request').first().json.body.message,
  session_id: $('Receive Chat Request').first().json.body.session_id || session.session_id || 'no-session',
  action: $('Receive Chat Request').first().json.body.action || 'default',
} }];

const client = $('Get Client Config').first().json;
const body = $('Check Token Valid').first().json;

if (!client || !client.id) throw new Error('Invalid client');
if (!client.active) throw new Error('Client account is inactive');
if (!body.message || !body.message.trim()) throw new Error('Message is required');

const role = body.role ?? 'public';
const roleHierarchy = {
  owner: ['public', 'staff', 'admin', 'owner'],
  admin: ['public', 'staff', 'admin'],
  staff: ['public', 'staff'],
  client: ['public'],
  guest: ['public']
};

const action = body.action || 'default';
const models = client.config.ai.models || {};
const resolvedModel = models[action] || models['default'] || {
  provider: 'ollama',
  model: client.config.ai.chat_model || client.config.ai.model,
  system_prompt: client.config.ai.system_prompt
};

return [{
  json: {
    message: body.message,
    role,
    allowed_roles: roleHierarchy[role] ?? ['public'],
    user_id: body.user_id,
    session_id: body.session_id,
    client_id: client.id,
    slug: client.slug,
    config: client.config,
    ollama_url: client.config.ai.ollama_url,
    embed_model: client.config.ai.embed_model,
    provider: resolvedModel.provider || 'ollama',
    chat_model: resolvedModel.model,
    qdrant_url: client.config.ai.qdrant_url,
    qdrant_collection: client.config.ai.qdrant_collection,
    search_limit: client.config.ai.search_limit,
    system_prompt: resolvedModel.system_prompt || `You are a helpful assistant for ${client.name}. Answer questions using only the provided context. If the context doesn\'t contain the answer, say you don\'t have that information.`,
    message_index: Date.now(),
  }
}];

const validated = $input.first().json;
return [{
  json: {
    message: validated.message,
    ollama_url: validated.ollama_url,
    chat_model: validated.chat_model,
    session_id: validated.session_id,
    user_id: validated.user_id,
    client_id: validated.client_id,
    system_prompt: `You are a helpful AI assistant. The user has provided content for you to analyze. Read it carefully and answer their request thoroughly and accurately. Be specific, structured, and professional in your response.`,
    context: '',
    sources: [],
    message_index: Date.now()
  }
}];

const response = $input.first().json.message.content;
const context = $('Build Direct Prompt').first().json;
return [{
  json: {
    response,
    sources: [],
    session_id: context.session_id,
    message_index: context.message_index
  }
}];

const hits = $input.first().json.result;
const validated = $('Validate Request').first().json;

const docHits = hits.filter(h => !h.payload.type || h.payload.type === 'document');
const knowledgeHits = hits.filter(h => h.payload.type === 'knowledge');
const historyHits = hits.filter(h => h.payload.type === 'chat_history' && h.score >= 0.85);

const knowledgeQuestions = new Set(
  knowledgeHits.map(h => h.payload.question?.toLowerCase().trim()).filter(Boolean)
);

const seenQuestions = new Set();
const dedupedHistory = [];
for (const h of historyHits) {
  const q = h.payload.question?.toLowerCase().trim();
  if (q && !knowledgeQuestions.has(q) && !seenQuestions.has(q)) {
    seenQuestions.add(q);
    dedupedHistory.push(h);
  }
}

const merged = [...docHits, ...knowledgeHits, ...dedupedHistory.slice(0, 2)]
  .sort((a, b) => b.score - a.score)
  .slice(0, validated.search_limit ?? 5);

return [{ json: { result: merged } }];

