let reranked;
try { reranked = $('Rerank Results').first().json.results ?? []; } catch(e) { reranked = []; }
const validated = $('Validate Request').first().json;

let historyRaw;
try { historyRaw = $('Fetch Session History').first().json.result; } catch(e) { historyRaw = null; }
const historyHits = historyRaw?.points ?? (Array.isArray(historyRaw) ? historyRaw : []);
const sorted = [...historyHits].sort((a, b) =>
  new Date(a.payload.timestamp) - new Date(b.payload.timestamp)
);
const historyText = sorted.length > 0
  ? 'Previous conversation:\n' + sorted.map(h =>
      `User: ${h.payload.question}\nAssistant: ${h.payload.answer}`
    ).join('\n\n')
  : '';

const savedContext = reranked.length === 0
  ? sorted.filter(h => h.payload.context).map(h => h.payload.context).join('\n\n')
  : '';

const docContext = reranked.length > 0
  ? reranked.map(c => c.section_text || c.text).join('\n\n---\n\n')
  : savedContext;

const context = [docContext, historyText].filter(Boolean).join('\n\n---\n\n');

const sources = reranked.map(c => ({
  source: c.source ?? 'Document',
  role: c.role ?? 'public',
  score: c.rerank_score,
  type: c.type ?? 'document'
}));

return [{
  json: {
    message: validated.message,
    context,
    sources,
    system_prompt: validated.system_prompt,
    chat_model: validated.chat_model,
    provider: validated.provider,
    ollama_url: validated.ollama_url,
    session_id: validated.session_id,
    user_id: validated.user_id,
    client_id: validated.client_id,
  }
}];

